  return seg.y1 === seg.y2;
}

function isVertical(seg) {
  return seg.x1 === seg.x2;
}

function normalizedSeg(seg) {
  let { x1, y1, x2, y2 } = seg;
  if (x1 === x2) {
    if (y1 > y2) [y1, y2] = [y2, y1];
  } else if (y1 === y2) {
    if (x1 > x2) [x1, x2] = [x2, x1];
  }
  return { x1, y1, x2, y2 };
}

function segmentsCross(a, b) {
  // Only consider perpendicular crossing at an interior point.
  const A = normalizedSeg(a);
  const B = normalizedSeg(b);
  if (isHorizontal(A) && isVertical(B)) {
    const y = A.y1;
    const x = B.x1;
    const aMinX = Math.min(A.x1, A.x2);
    const aMaxX = Math.max(A.x1, A.x2);
    const bMinY = Math.min(B.y1, B.y2);
    const bMaxY = Math.max(B.y1, B.y2);
    const inA = x > aMinX && x < aMaxX;
    const inB = y > bMinY && y < bMaxY;
    return inA && inB;
  }
  if (isVertical(A) && isHorizontal(B)) return segmentsCross(B, A);
  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [k, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(k);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
  }

  return counts;
}

function isAdjacentVisible(islands, from, to) {
  if (from.id === to.id) return false;
  if (from.x !== to.x && from.y !== to.y) return false;

  const sameRow = from.y === to.y;
  const sameCol = from.x === to.x;

  if (sameRow) {
    const y = from.y;
    const minX = Math.min(from.x, to.x);
    const maxX = Math.max(from.x, to.x);
    for (const isl of islands) {
      if (isl.id === from.id || isl.id === to.id) continue;
      if (isl.y === y && isl.x > minX && isl.x < maxX) return false;
    }
    return true;
  }

  if (sameCol) {
    const x = from.x;
    const minY = Math.min(from.y, to.y);
    const maxY = Math.max(from.y, to.y);
    for (const isl of islands) {
      if (isl.id === from.id || isl.id === to.id) continue;
      if (isl.x === x && isl.y > minY && isl.y < maxY) return false;
    }
    return true;
  }

  return false;
}

function wouldCrossExisting(bridges, from, to, ignoreKey) {
  const candidate = normalizedSeg({ x1: from.x, y1: from.y, x2: to.x, y2: to.y });
  for (const [k, n] of bridges.entries()) {
    if (!n) continue;
    if (k === ignoreKey) continue;
    const seg = normalizedSeg(parseKey(k));
    if (segmentsCross(candidate, seg)) return true;
  }
  return false;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!isAdjacentVisible(islands, from, to)) {
    return { valid: false, error: ERROR_NON_ADJACENT };
  }

  const k = keyForBridge(from, to);
  const current = bridges.get(k) ?? 0;
  const next = current + delta;

  if (next < 0) return { valid: true, error: null };
  if (next > 2) return { valid: false, error: ERROR_MAX_PAIR };

  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) ?? 0;
  const toCount = counts.get(to.id) ?? 0;

  if (fromCount + delta > from.value || toCount + delta > to.value) {
    return { valid: false, error: ERROR_EXCEED };
  }

  if (wouldCrossExisting(bridges, from, to, k) && next > 0) {
    return { valid: false, error: ERROR_CROSS };
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length <= 1) return true;

  const posToId = new Map(islands.map((i) => [`${i.x},${i.y}`, i.id]));
  const adj = new Map();
  for (const isl of islands) adj.set(isl.id, []);

  for (const [k, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(k);
    const aId = posToId.get(`${x1},${y1}`);
    const bId = posToId.get(`${x2},${y2}`);
    if (aId === undefined || bId === undefined) continue;
    adj.get(aId).push(bId);
    adj.get(bId).push(aId);
  }

  const start = islands[0].id;
  const seen = new Set([start]);
  const q = [start];
  while (q.length) {
    const cur = q.shift();
    for (const nxt of adj.get(cur) || []) {
      if (!seen.has(nxt)) {
        seen.add(nxt);
        q.push(nxt);
      }
    }
  }

  return seen.size === islands.length;
}

function noCrossings(bridges) {
  const segs = [];
  for (const [k, n] of bridges.entries()) {
    if (!n) continue;
    segs.push(normalizedSeg(parseKey(k)));
  }
  for (let i = 0; i < segs.length; i++) {
    for (let j = i + 1; j < segs.length; j++) {
      if (segmentsCross(segs[i], segs[j])) return false;
    }
  }
  return true;
}

export function isVictory(islands, bridges) {
  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }
  if (!noCrossings(bridges)) return false;
  if (!checkConnectivity(islands, bridges)) return false;
  return true;
}
