import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  canAddBridge,
  computeCurrentCounts,
  isVictory,
  keyForBridge,
} from './utils/hashiLogic';

const GRID = 40;
const WIDTH = 800;
const HEIGHT = 600;

function islandPx(i) {
  return { cx: i.x * GRID, cy: i.y * GRID };
}

function bridgeLinesFor(islandsByPos, key, count) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  const a = islandsByPos.get(`${x1},${y1}`);
  const b = islandsByPos.get(`${x2},${y2}`);
  if (!a || !b) return [];

  const p1 = { x: x1 * GRID, y: y1 * GRID };
  const p2 = { x: x2 * GRID, y: y2 * GRID };

  const isH = y1 === y2;
  const offset = 6;

  if (count === 1) {
    return [
      {
        x1: p1.x,
        y1: p1.y,
        x2: p2.x,
        y2: p2.y,
      },
    ];
  }

  if (count === 2) {
    if (isH) {
      return [
        { x1: p1.x, y1: p1.y - offset, x2: p2.x, y2: p2.y - offset },
        { x1: p1.x, y1: p1.y + offset, x2: p2.x, y2: p2.y + offset },
      ];
    }
    return [
      { x1: p1.x - offset, y1: p1.y, x2: p2.x - offset, y2: p2.y },
      { x1: p1.x + offset, y1: p1.y, x2: p2.x + offset, y2: p2.y },
    ];
  }

  return [];
}

function findNeighbor(islands, from, dir) {
  // dir: 'left'|'right'|'up'|'down'
  let best = null;
  for (const isl of islands) {
    if (isl.id === from.id) continue;
    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
      if (!best || isl.x > best.x) best = isl;
    }
    if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
      if (!best || isl.x < best.x) best = isl;
    }
    if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
      if (!best || isl.y > best.y) best = isl;
    }
    if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
      if (!best || isl.y < best.y) best = isl;
    }
  }
  return best;
}

export default function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const puzzle = puzzles[puzzleIndex];

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null); // for mouse pairing and keyboard selection
  const [cursorId, setCursorId] = useState(puzzle.islands[0]?.id ?? 0);
  const [error, setError] = useState(null);

  const svgRef = useRef(null);

  const islands = puzzle.islands;

  const islandsById = useMemo(() => {
    const m = new Map();
    for (const i of islands) m.set(i.id, i);
    return m;
  }, [islands]);

  const islandsByPos = useMemo(() => {
    const m = new Map();
    for (const i of islands) m.set(`${i.x},${i.y}`, i);
    return m;
  }, [islands]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function clearErrorOnValid(nextError) {
    if (!nextError) setError(null);
  }

  function applyBridgeDelta(from, to, delta) {
    const res = canAddBridge(islands, bridges, from, to, delta);
    if (!res.valid) {
      setError(res.error);
      return;
    }

    const k = keyForBridge(from, to);
    const current = bridges.get(k) ?? 0;
    const next = Math.max(0, Math.min(2, current + delta));

    const nextMap = new Map(bridges);
    if (next === 0) nextMap.delete(k);
    else nextMap.set(k, next);

    setBridges(nextMap);
    clearErrorOnValid(null);
  }

  function cycleBridge(from, to) {
    const k = keyForBridge(from, to);
    const cur = bridges.get(k) ?? 0;
    const delta = cur === 0 ? 1 : cur === 1 ? 1 : -2; // 0->1->2->0
    applyBridgeDelta(from, to, delta);
  }

  function removeBridge(from, to) {
    const k = keyForBridge(from, to);
    const cur = bridges.get(k) ?? 0;
    if (cur === 0) return;
    const nextMap = new Map(bridges);
    nextMap.delete(k);
    setBridges(nextMap);
    setError(null);
  }

  function onIslandClick(e, isl) {
    // Ctrl+click removes existing bridge between selected and this? Spec: Ctrl+click on existing bridge removes it.
    // For island clicks: follow spec - first click selects; second click different island toggles; then clear selection.
    e.preventDefault();
    svgRef.current?.focus();

    if (selectedId === null) {
      setSelectedId(isl.id);
      setCursorId(isl.id);
      return;
    }

    if (selectedId === isl.id) {
      setSelectedId(null);
      return;
    }

    const from = islandsById.get(selectedId);
    const to = isl;
    cycleBridge(from, to);
    setSelectedId(null);
  }

  function onSvgContextMenu(e) {
    e.preventDefault();
  }

  function onBridgePointerDown(e, key) {
    const isRemove = e.button === 2 || e.ctrlKey;
    if (!isRemove) return;
    e.preventDefault();
    const [x1, y1, x2, y2] = key.split(',').map(Number);
    const a = islandsByPos.get(`${x1},${y1}`);
    const b = islandsByPos.get(`${x2},${y2}`);
    if (a && b) removeBridge(a, b);
  }

  useEffect(() => {
    // when puzzle changes, fully reset bridges and selection and cursor
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setCursorId(puzzles[puzzleIndex].islands[0]?.id ?? 0);
  }, [puzzleIndex]);

  useEffect(() => {
    const el = svgRef.current;
    if (!el) return;

    function onKeyDown(e) {
      const cur = islandsById.get(cursorId) ?? islands[0];
      if (!cur) return;

      if (e.key === 'Escape') {
        setSelectedId(null);
        setError(null);
        return;
      }

      if (e.key === 'Enter') {
        e.preventDefault();
        if (selectedId === null) {
          setSelectedId(cur.id);
        } else {
          if (selectedId === cur.id) {
            setSelectedId(null);
          } else {
            const from = islandsById.get(selectedId);
            const to = cur;
            cycleBridge(from, to);
            setSelectedId(null);
          }
        }
        return;
      }

      const dirKey =
        e.key === 'ArrowLeft'
          ? 'left'
          : e.key === 'ArrowRight'
            ? 'right'
            : e.key === 'ArrowUp'
              ? 'up'
              : e.key === 'ArrowDown'
                ? 'down'
                : null;

      if (!dirKey) return;
      e.preventDefault();

      const neigh = findNeighbor(islands, cur, dirKey);
      if (neigh) {
        setCursorId(neigh.id);
        // selection stays (if any) while moving cursor
      }
    }

    el.addEventListener('keydown', onKeyDown);
    return () => el.removeEventListener('keydown', onKeyDown);
  }, [cursorId, islands, islandsById, selectedId]);

  const bridgeEntries = Array.from(bridges.entries()).filter(([, n]) => n > 0);

  return (
    <div className="app-root">
      <div className="ui-bar">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleIndex}
            onChange={(e) => setPuzzleIndex(Number(e.target.value))}
          >
            <option value={0}>Easy</option>
            <option value={1}>Medium</option>
            <option value={2}>Hard</option>
          </select>
        </label>
        <button
          onClick={() => {
            setBridges(new Map());
            setSelectedId(null);
            setError(null);
            svgRef.current?.focus();
          }}
        >
          Reset
        </button>
        <span className="status">
          Selected: {selectedId === null ? '-' : selectedId}
        </span>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg
        ref={svgRef}
        className="board-svg"
        width={WIDTH}
        height={HEIGHT}
        viewBox={`0 0 ${WIDTH} ${HEIGHT}`}
        tabIndex={0}
        onContextMenu={onSvgContextMenu}
        style={{ outline: 'none' }}
      >
        {/* Bridges */}
        <g className="bridges">
          {bridgeEntries.flatMap(([k, n]) => {
            const segs = bridgeLinesFor(islandsByPos, k, n);
            return segs.map((s, idx) => (
              <line
                key={`${k}:${idx}`}
                x1={s.x1}
                y1={s.y1}
                x2={s.x2}
                y2={s.y2}
                stroke="#0f0"
                strokeWidth={4}
                shapeRendering="crispEdges"
                onPointerDown={(e) => onBridgePointerDown(e, k)}
                onContextMenu={(e) => {
                  e.preventDefault();
                  onBridgePointerDown({ ...e, button: 2 }, k);
                }}
              />
            ));
          })}
        </g>

        {/* Keyboard cursor (must not be a circle) */}
        {(() => {
          const cur = islandsById.get(cursorId);
          if (!cur) return null;
          const p = islandPx(cur);
          const size = 30;
          return (
            <rect
              x={p.cx - size / 2}
              y={p.cy - size / 2}
              width={size}
              height={size}
              fill="none"
              stroke="#0f0"
              strokeWidth={2}
              strokeDasharray="4 4"
            />
          );
        })()}

        {/* Islands */}
        <g className="islands">
          {islands.map((isl) => {
            const p = islandPx(isl);
            const isSelected = selectedId === isl.id;
            const curCount = counts.get(isl.id) ?? 0;
            return (
              <g
                key={isl.id}
                transform={`translate(${p.cx},${p.cy})`}
                onClick={(e) => onIslandClick(e, isl)}
              >
                <circle
                  r={14}
                  fill="black"
                  stroke={isSelected ? '#9f9' : '#0f0'}
                  strokeWidth={2}
                />
                <text
                  x={0}
                  y={5}
                  textAnchor="middle"
                  fontFamily="monospace"
                  fontSize={14}
                  fill="#0f0"
                >
                  {isl.value}
                </text>
                <text
                  x={0}
                  y={28}
                  textAnchor="middle"
                  fontFamily="monospace"
                  fontSize={10}
                  fill="#0f0"
                >
                  {curCount}/{isl.value}
                </text>
              </g>
            );
          })}
        </g>
      </svg>
    </div>
  );
}
