export const ERROR_MAX_PAIR = "Max 2 bridges per pair";
export const ERROR_EXCEED = "Island would exceed its number";
export const ERROR_CROSS = "Bridges would cross";

export function keyForBridge(a, b) {
  // a,b are {x,y} in grid units
  const ax = a.x;
  const ay = a.y;
  const bx = b.x;
  const by = b.y;
  if (ax < bx || (ax === bx && ay <= by)) return `${ax},${ay},${bx},${by}`;
  return `${bx},${by},${ax},${ay}`;
}

function parseKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map((n) => Number(n));
  return { x1, y1, x2, y2 };
}

function isHorizontal(seg) {
  return seg.y1 === seg.y2;
}

function isVertical(seg) {
  return seg.x1 === seg.x2;
}

function normalizedSeg(seg) {
  let { x1, y1, x2, y2 } = seg;
  if (x1 === x2) {
    if (y1 > y2) [y1, y2] = [y2, y1];
  } else if (y1 === y2) {
    if (x1 > x2) [x1, x2] = [x2, x1];
  }
  return { x1, y1, x2, y2 };
}

